CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TYPE "UserRole" AS ENUM ('ADMIN','MANAGER','VIEWER');
CREATE TYPE "ProjectType" AS ENUM ('VILLA','TOWNHOUSE','CONDOMINIUM','MIXED_USE');
CREATE TYPE "OwnershipType" AS ENUM ('FREEHOLD','LEASEHOLD','FOREIGN_FREEHOLD','COMPANY_OWNERSHIP');
CREATE TYPE "ConstructionStatus" AS ENUM ('PLANNING','OFF_PLAN','UNDER_CONSTRUCTION','COMPLETED','READY_TO_MOVE_IN');
CREATE TYPE "PropertyType" AS ENUM ('VILLA','TOWNHOUSE','CONDOMINIUM','PENTHOUSE');
CREATE TYPE "MediaType" AS ENUM ('IMAGE','VIDEO','FLOORPLAN','DOCUMENT');
CREATE TABLE users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, role "UserRole" NOT NULL DEFAULT 'VIEWER', created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE developers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), developer_name TEXT NOT NULL, website TEXT, years_in_business INT, completed_projects INT, units_delivered INT, reputation_score DECIMAL, financial_stability_score DECIMAL, notes TEXT, "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(), "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE projects (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), developer_id UUID NOT NULL REFERENCES developers(id) ON DELETE CASCADE, project_name TEXT NOT NULL, project_type "ProjectType" NOT NULL, location TEXT NOT NULL, submarket TEXT, latitude DECIMAL, longitude DECIMAL, ownership_type "OwnershipType" NOT NULL, construction_status "ConstructionStatus" NOT NULL, launch_date TIMESTAMPTZ, handover_date TIMESTAMPTZ, total_units INT, units_sold INT, units_available INT, project_description TEXT, "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(), "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE properties (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE, property_code TEXT UNIQUE NOT NULL, property_type "PropertyType" NOT NULL, bedrooms INT NOT NULL, bathrooms INT NOT NULL, interior_sqm DECIMAL NOT NULL, land_sqm DECIMAL, private_pool BOOLEAN NOT NULL DEFAULT false, garden BOOLEAN NOT NULL DEFAULT false, parking BOOLEAN NOT NULL DEFAULT false, elevator BOOLEAN NOT NULL DEFAULT false, furnished BOOLEAN NOT NULL DEFAULT false, smart_home BOOLEAN NOT NULL DEFAULT false, pet_friendly BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(), "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE property_financials (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, list_price DECIMAL NOT NULL, currency TEXT NOT NULL DEFAULT 'THB', price_per_sqm DECIMAL, reservation_fee DECIMAL, deposit_required DECIMAL, payment_plan TEXT, maintenance_fee DECIMAL, sinking_fund DECIMAL, transfer_tax DECIMAL, ownership_tax DECIMAL, rental_management_fee DECIMAL);
CREATE TABLE property_healthcare (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, nearest_hospital TEXT, hospital_distance_km DECIMAL, hospital_drive_minutes INT, english_speaking_doctors BOOLEAN NOT NULL DEFAULT false, emergency_services BOOLEAN NOT NULL DEFAULT false, specialist_services BOOLEAN NOT NULL DEFAULT false, cardiology BOOLEAN NOT NULL DEFAULT false, oncology BOOLEAN NOT NULL DEFAULT false, dialysis BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE property_accessibility (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, beach_distance_km DECIMAL, grocery_distance_km DECIMAL, pharmacy_distance_km DECIMAL, restaurant_distance_km DECIMAL, walkability_score INT);
CREATE TABLE property_airport_access (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, airport_distance_km DECIMAL, airport_drive_minutes INT);
CREATE TABLE property_safety (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, crime_rating INT, walking_safety INT, night_safety INT, security_rating INT);
CREATE TABLE property_expat_community (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, expat_density INT, social_clubs INT, churches INT, golf_courses INT, fitness_centers INT);
CREATE TABLE property_management (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, security BOOLEAN NOT NULL DEFAULT false, reception BOOLEAN NOT NULL DEFAULT false, maintenance BOOLEAN NOT NULL DEFAULT false, rental_management BOOLEAN NOT NULL DEFAULT false, concierge BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE property_lifestyle (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, beach_score INT, golf_score INT, marina_score INT, restaurant_score INT, shopping_score INT, wellness_score INT);
CREATE TABLE property_scores (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID UNIQUE NOT NULL REFERENCES properties(id) ON DELETE CASCADE, healthcare_score INT NOT NULL, accessibility_score INT NOT NULL, airport_score INT NOT NULL, expat_score INT NOT NULL, safety_score INT NOT NULL, management_score INT NOT NULL, lifestyle_score INT NOT NULL, retirement_score INT NOT NULL, retirement_grade TEXT NOT NULL, calculated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE property_media (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), property_id UUID NOT NULL REFERENCES properties(id) ON DELETE CASCADE, media_type "MediaType" NOT NULL, file_url TEXT NOT NULL, title TEXT, "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX projects_developer_id_idx ON projects(developer_id); CREATE INDEX properties_project_id_idx ON properties(project_id); CREATE INDEX property_media_property_id_idx ON property_media(property_id);
